### Text Generation with Transformers.js

Source: https://context7.com/huggingface/transformers.js/llms.txt

Perform text generation using the Transformers.js library. This snippet shows basic generation, generation with parameters like max_new_tokens and temperature, and chat-style generation with system and user messages.

```javascript
import { pipeline } from '@huggingface/transformers';

// Basic text generation
const generator = await pipeline(
    'text-generation',
    'onnx-community/Qwen2.5-0.5B-Instruct',
    { dtype: 'q4' }
);

// Simple generation with parameters
const result = await generator('Once upon a time', {
    max_new_tokens: 50,
    temperature: 0.9,
    do_sample: true,
    top_k: 50,
    top_p: 0.95,
    repetition_penalty: 1.2,
    no_repeat_ngram_size: 3
});
console.log(result);
// Output: [{
//   generated_text: 'Once upon a time, in a land far away, there lived a young prince...'
// }]

// Chat-style generation with message format
const messages = [
    { role: "system", content: "You are a helpful assistant." },
    { role: "user", content: "Write a haiku about programming." }
];

const chatResult = await generator(messages, {
    max_new_tokens: 100,
    do_sample: false  // Greedy decoding for deterministic output
});
console.log(chatResult[0].generated_text);
// Output: [
//   { role: "system", content: "You are a helpful assistant." },
//   { role: "user", content: "Write a haiku about programming." },
//   { role: "assistant", content: "Code flows like water\nBugs hide in the silent night\nDebug brings the dawn" }
// ]
```

